    saju_header_lifetime: '\u25C8 An\u00e1lise Profunda de Vida Completa',
    saju_lifetime_career_title: '\u25B8 Aptid\u00e3o Profissional e Fortuna Financeira',
    saju_lifetime_career_wood_yang: 'Madeira Yang: l\u00edder nato, empres\u00e1rio, pol\u00edtico, arquiteto, educador. Sucesso como pioneiro. Riqueza cresce significativamente a partir da meia-idade.',
    saju_lifetime_career_wood_yin: 'Madeira Yin: designer, escritor, conselheiro, florista, moda. Grande capacidade colaborativa. Riqueza acumula-se de forma est\u00e1vel.',
    saju_lifetime_career_fire_yang: 'Fogo Yang: artista, locutor, marketing, vendas, diplomata. Brilha em pap\u00e9is p\u00fablicos. Riqueza din\u00e2mica.',
    saju_lifetime_career_fire_yin: 'Fogo Yin: pesquisador, professor, psic\u00f3logo, artista, m\u00e9dico. Especialista profundo. Riqueza est\u00e1vel e ascendente.',
    saju_lifetime_career_earth_yang: 'Terra Yang: im\u00f3veis, constru\u00e7\u00e3o, agricultura, mediador, funcion\u00e1rio p\u00fablico. Excelente gestor. Grande fortuna em propriedades.',
    saju_lifetime_career_earth_yin: 'Terra Yin: professor, chef, agricultor, assistente social, RH. Dilig\u00eancia constante \u00e9 a chave. Riqueza por poupan\u00e7a paciente.',
    saju_lifetime_career_metal_yang: 'Metal Yang: militar, pol\u00edcia, advogado, cirurgi\u00e3o, CEO. Julgamento afiado em crises. Riqueza por investimentos ousados.',
    saju_lifetime_career_metal_yin: 'Metal Yin: joalheiro, designer, m\u00fasico, programador, t\u00e9cnico de precis\u00e3o. Esp\u00edrito artes\u00e3o. Riqueza cresce com a expertise.',
    saju_lifetime_career_water_yang: '\u00c1gua Yang: acad\u00eamico, fil\u00f3sofo, comerciante, viagens, TI. Talento interdisciplinar global. Riqueza flui como \u00e1gua.',
    saju_lifetime_career_water_yin: '\u00c1gua Yin: conselheiro, curador, adivinho, escritor, assistente. Perspic\u00e1cia intuitiva. Riqueza chega silenciosa mas constantemente.',
    saju_lifetime_relation_title: '\u25B8 Relacionamentos e Conex\u00f5es Destinadas',
    saju_lifetime_rel_wood_yang: 'Madeira Yang: forte primeira impress\u00e3o. V\u00ednculos duradouros. Aprenda a ceder. Benfeitor: energia de Fogo.',
    saju_lifetime_rel_wood_yin: 'Madeira Yin: sociabilidade suave, popular romanticamente. N\u00e3o disperse energia. Benfeitor: energia de Metal.',
    saju_lifetime_rel_fire_yang: 'Fogo Yang: atrai pessoas naturalmente. N\u00e3o negligencie os pr\u00f3ximos. Benfeitor: energia de \u00c1gua.',
    saju_lifetime_rel_fire_yin: 'Fogo Yin: la\u00e7os profundos com poucos. Expresse sentimentos abertamente. Benfeitor: energia de Madeira.',
    saju_lifetime_rel_earth_yang: 'Terra Yang: ganha confian\u00e7a ampla. Mantenha limites saud\u00e1veis. Benfeitor: energia de Fogo.',
    saju_lifetime_rel_earth_yin: 'Terra Yin: dedicado e caloroso, mas cuide-se tamb\u00e9m. Benfeitor: energia de Metal.',
    saju_lifetime_rel_metal_yang: 'Metal Yang: direto e confi\u00e1vel, mas palavras afiadas. Aprenda express\u00e3o suave. Benfeitor: energia de Fogo.',
    saju_lifetime_rel_metal_yin: 'Metal Yin: seletivo mas profundamente leal. Solte o perfeccionismo. Benfeitor: energia de \u00c1gua.',
    saju_lifetime_rel_water_yang: '\u00c1gua Yang: cora\u00e7\u00e3o aberto mas precisa de liberdade. Benfeitor: energia de Terra.',
    saju_lifetime_rel_water_yin: '\u00c1gua Yin: intui\u00e7\u00e3o penetrante. N\u00e3o se isole por sensibilidade. Benfeitor: energia de Madeira.',
    saju_lifetime_wealth_title: '\u25B8 Fortuna Financeira Vital\u00edcia',
    saju_lifetime_wealth_strong: 'Estrelas de Riqueza concedem habilidade financeira natural. Riqueza Direta traz renda est\u00e1vel; Riqueza Indireta traz fortuna especulativa.',
    saju_lifetime_wealth_weak: 'Estrelas de Riqueza sutis, mas recursos fluem por educa\u00e7\u00e3o e talento criativo. Invista em desenvolvimento pessoal.',
    saju_lifetime_wealth_none: 'Sem Estrelas de Riqueza, mas menos apego material significa maior riqueza espiritual. Suas habilidades atraem recursos naturalmente.',
    saju_header_year_detail: '\u25C8 Fortuna Detalhada de {year}',
    saju_year_energy_title: '\u25B8 Energia do Ano e Sua Carta',
    saju_year_energy_text: '{year} \u00e9 o ano de {yearStem}{yearBranch}, dominado por {yearOheng}. Seu Mestre do Dia {dayStem} e o Tronco Celestial {yearStem} formam rela\u00e7\u00e3o {yukchin}: {yukchinMeaning}',
    saju_year_monthly_title: '\u25B8 Fluxo Sazonal de Fortuna',
