    saju_year_love_pyeonjae: 'Oportunidades rom\u00e2nticas abundantes. Atratividade elevada.',
    saju_year_love_jeongjae: 'Amor est\u00e1vel e devotado poss\u00edvel. Excelente ano para casamento.',
