    saju_header_today: '\u25C8 Fortuna de Hoje ({day}/{month})',
    saju_today_energy_title: '\u25B8 Energia de Hoje',
    saju_today_energy_text: 'Hoje \u00e9 dia {dayStem}{dayBranch}, fluindo com energia {dayOheng}. Seu Mestre do Dia {myStem} e o Tronco {dayStem} formam rela\u00e7\u00e3o {yukchin}: {reading}',
    saju_today_advice_title: '\u25B8 Guia de A\u00e7\u00e3o de Hoje',
    saju_today_advice_bigyeon: 'Hoje favorece a\u00e7\u00e3o independente. Mantenha confian\u00e7a ante competi\u00e7\u00e3o. Evite teimosia.',
    saju_today_advice_geopjae: 'Vigile suas finan\u00e7as hoje. Evite compras impulsivas e empr\u00e9stimos.',
    saju_today_advice_siksin: 'Dia perfeito para aproveitar. Boa comida e m\u00fasica recarregam energia. Ideias criativas fluem.',
